var aer = [];
for(var i = 0; i < skillz.data.allExerciseRevisions.length; i++) {
	aer.push(skillz.data.allExerciseRevisions[i]);
}
aer.sort(function(a, b) {
	return a.title.localeCompare(b.title);
});
var thelist = document.getElementById('list');
var dewit = function(page) {
	thelist.innerHTML = '';
	for(var i = page*1000; i < Math.min(aer.length, page*1000+1000); i++) {
		var theli = '<li>';
		//theli += '<a href="https://www.khanacademy.org/math/math1/x89d82521517266d4:algebra-foundation/x89d82521517266d4:variables-intro/e/' + aer[i].slug + '">' + aer[i].title + '</a>';
		theli += '<a href="https://www.khanacademy.org/e/' + aer[i].slug + '">' + aer[i].title + '</a>';
		//console.log(theli);
		theli += '</li>';
		thelist.innerHTML += theli;
	}
}
var search = function() {
	thelist.innerHTML = '';
	var results = 0;
	var query = document.getElementById('txt').value.toLowerCase();
	for(var i = 0; i < aer.length; i++) {
		if(aer[i].title.toLowerCase().includes(query)) {
			var theli = '<li>';
			//theli += '<a href="https://www.khanacademy.org/math/math1/x89d82521517266d4:algebra-foundation/x89d82521517266d4:variables-intro/e/' + aer[i].slug + '">' + aer[i].title + '</a>';
			theli += '<a href="https://www.khanacademy.org/e/' + aer[i].slug + '">' + aer[i].title + '</a>';
			//console.log(theli);
			theli += '</li>';
			thelist.innerHTML += theli;
			results++;
		}
		if(results >= 1000) {
			break;
		}
	}
}